var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"인원이 다 모인 것 같으니 이제부터 작전을 설명하지.","JPN":"全員揃ったみたいだから、これから作戦の説明をする。","ENG":"Since it seems everyone's here, I'll fill you in on the operation.","TWN":"大家都到齊了，那現在開始說明作戰規劃吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"작전의 목표는 두 가지다.","JPN":"作戦の目標は二つ。","ENG":"We have two objectives.","TWN":"本次作戰的目標有兩個。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"첫째는 차원의 틈에 숨어 있는 리플레이서 기함, 뉴 오하이오의 좌표를 찾아내는 것.","JPN":"一つ目は次元の狭間に隠れているリプレイサー総旗艦、ニューオハイオの座標を見つけること。","ENG":"First, we find the coordinates of the New Ohio, flagship of the Replacer Syndicate, now hiding between dimensions.","TWN":"第一，找出隱藏在次元縫隙裡的克隆集團旗艦，新俄亥俄的座標。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그리고 두 번째는 뉴 오하이오의 차원도약 기능을 마비시키고 관리국 태스크포스들을 불러 리플레이서를 격멸하는 것.","JPN":"そして二つ目は、ニューオハイオの次元跳躍機能を麻痺させた後、\\n管理局のタスクフォースを呼び出してリプレイサーを撃滅させること。","ENG":"Second, we cripple the New Ohio's dimension jump system, call the Administration TASKFORCEs, and eliminate the Replacer forces.","TWN":"接著第二，癱瘓新俄亥俄的次元躍遷功能，並召集管理局的特遣勢力，擊敗克隆集團。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......좋아, 그런데 놈들을 어떻게 찾지?","JPN":"……了解、だけど、どうやって奴らを見つけるの？","ENG":"Fine. But how are you going to find them?","TWN":"……很好。但我們要怎麼找到那些傢伙呢？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"간단해.","JPN":"簡単だ。","ENG":"It's simple.","TWN":"很簡單。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이동형이건 아니건 불멸체 코어는 단말과 어떤 식으로든 연결되어 있어야 한다.","JPN":"移動型かどうかにかかわらず、不滅体コアは何らかの方法で端末と繋がってなければならない。","ENG":"Mobile or stationary, the Immortal System Core must stay connected to the terminals.","TWN":"無論是不是可移動型，不滅者核心都得以某種形式和終端連接著。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래야 부서진 로스트 쉽을 복구할 수가 있으니까.","JPN":"そうしてこそ、壊れたロストシップを復旧することができるんだ。","ENG":"Or it would be impossible for them to restore the destroyed Lost Ships.","TWN":"因為只有這樣，才能修補好被破壞的失落艦船。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 연결은 차원간섭파를 통해 이루어지기 때문에 일반적으로는 추적이 불가능해.","JPN":"その繫がりは次元干渉波を介しているから、通常は追跡できないんだ。","ENG":"And this connection is made through dimension interference waves, which makes it impossible to trace.","TWN":"而這個連接是通過次元干涉波進行的，所以一般來說，是不可能追蹤到的。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만...... 사실 뉴 오하이오의 통신 출력만으로는 불멸체 코어와 전 세계의 로스트 쉽 간의 데이터 링크를 유지할 수 없어.","JPN":"だが……実は、ニューオハイオの通信出力だけじゃ、\\n不滅体コアと世界中のロストシップとのデータリンクが維持できないのが現状だ。","ENG":"However, the output of the communication device equipped on the New Ohio isn't enough to maintain the data link between the Immortal System Core and all the Lost Ships around the world.","TWN":"但是……實際上，光靠新俄亥俄的通信輸出，是無法維持不滅者核心和全世界失落艦船之間的數據連結的。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래서 불멸체 코어의 차원간섭파를 전 세계로 송출해 주는 허브가 존재한다.","JPN":"そのため、不滅体コアの次元干渉波を世界中に発信するハブが存在するんだよ。","ENG":"This is the reason they're using hubs that transmit the dimension interference waves of the Immortal System Core to the entire world.","TWN":"所以，應該還存在著向全世界傳送不滅者核心次元干涉波的集線器。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"허브?","JPN":"ハブ？","ENG":"Hubs?","TWN":"集線器？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래, 휴대폰 기지국이라고 하면 이해하기 쉽겠지.","JPN":"そうだ、携帯基地局というとしっくりくるかもな。","ENG":"Think of them as cell towers of telecommunication companies.","TWN":"對，妳就想成是手機的基地台，這樣就很容易理解了。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우리가 찾아야 할 건 바로 이 녀석들이다.","JPN":"俺らが探すのは、まさにそいつらだ。","ENG":"And these hubs are what we're after.","TWN":"我們要找的，正是這個東西。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서가 만들어 낸 차원간섭파 증폭용 자율방어 융합체.","JPN":"リプレイサーが作り出した、次元干渉波増幅用の自律防御融合体。","ENG":"The Replacers' autonomous defense hybrider created to amplify dimension interference waves,","TWN":"克隆集團製造出的次元干涉波增幅用自動防禦融合體。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"통칭, 어보미네이션.","JPN":"通称、アボミネーション。","ENG":"otherwise known as Abominations.","TWN":"通稱，憎惡。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐...... 뭐야, 저게?","JPN":"な……なんだ、あれ？","ENG":"W-what's that thing?","TWN":"那……那是什麼鬼啊？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ABOMINATION_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"끔찍하게 생겼네...... 취향 나쁘군.","JPN":"うわ……趣味悪い。","ENG":"It looks horrendous. Yuk.","TWN":"長得真嚇人呢……真是奇怪的嗜好啊。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ABOMINATION_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};